import{_ as e,c as l,o as r,ag as i}from"./chunks/framework.GdcW6lnn.js";const P=JSON.parse('{"title":"Типи API","description":"","frontmatter":{},"headers":[],"relativePath":"basics_api/api-types.md","filePath":"basics_api/api-types.md"}'),t={name:"basics_api/api-types.md"};function o(h,a,d,s,n,c){return r(),l("div",null,a[0]||(a[0]=[i('<h1 id="типи-api" tabindex="-1">Типи API <a class="header-anchor" href="#типи-api" aria-label="Permalink to “Типи API”">​</a></h1><p>У сучасній розробці існує кілька основних типів API. Кожен має свої особливості, призначення та сферу застосування.</p><hr><h2 id="_1-rest-api-representational-state-transfer" tabindex="-1">1. REST API (Representational State Transfer) <a class="header-anchor" href="#_1-rest-api-representational-state-transfer" aria-label="Permalink to “1. REST API (Representational State Transfer)”">​</a></h2><p><strong>REST</strong> — найпопулярніший тип API, який використовує HTTP-запити.</p><h3 id="🔹-основні-характеристики" tabindex="-1">🔹 Основні характеристики: <a class="header-anchor" href="#🔹-основні-характеристики" aria-label="Permalink to “🔹 Основні характеристики:”">​</a></h3><ul><li>Працює через протокол HTTP/HTTPS</li><li>Використовує методи: <code>GET</code>, <code>POST</code>, <code>PUT</code>, <code>DELETE</code>, <code>PATCH</code></li><li>Повертає дані у форматі JSON або XML</li><li>Підтримує чітку ієрархію ресурсів (наприклад, <code>/users/1/posts</code>)</li></ul><h3 id="✅-переваги" tabindex="-1">✅ Переваги: <a class="header-anchor" href="#✅-переваги" aria-label="Permalink to “✅ Переваги:”">​</a></h3><ul><li>Простий у використанні</li><li>Добре підходить для публічних API</li><li>Широко підтримується</li></ul><h3 id="❌-недоліки" tabindex="-1">❌ Недоліки: <a class="header-anchor" href="#❌-недоліки" aria-label="Permalink to “❌ Недоліки:”">​</a></h3><ul><li>Іноді повертає надмірну або недостатню кількість даних</li><li>Не підходить для складних запитів</li></ul><hr><h2 id="_2-soap-api-simple-object-access-protocol" tabindex="-1">2. SOAP API (Simple Object Access Protocol) <a class="header-anchor" href="#_2-soap-api-simple-object-access-protocol" aria-label="Permalink to “2. SOAP API (Simple Object Access Protocol)”">​</a></h2><p><strong>SOAP</strong> — старіший протокол, який працює через XML-повідомлення.</p><h3 id="🔹-основні-характеристики-1" tabindex="-1">🔹 Основні характеристики: <a class="header-anchor" href="#🔹-основні-характеристики-1" aria-label="Permalink to “🔹 Основні характеристики:”">​</a></h3><ul><li>Використовує тільки XML</li><li>Передбачає строгий формат запиту й відповіді</li><li>Часто використовується в корпоративному середовищі</li><li>Має вбудовані механізми безпеки (WS-Security)</li></ul><h3 id="✅-переваги-1" tabindex="-1">✅ Переваги: <a class="header-anchor" href="#✅-переваги-1" aria-label="Permalink to “✅ Переваги:”">​</a></h3><ul><li>Надійність</li><li>Підтримка транзакцій</li><li>Високий рівень безпеки</li></ul><h3 id="❌-недоліки-1" tabindex="-1">❌ Недоліки: <a class="header-anchor" href="#❌-недоліки-1" aria-label="Permalink to “❌ Недоліки:”">​</a></h3><ul><li>Складний у реалізації</li><li>Об’ємні запити</li></ul><hr><h2 id="_3-graphql" tabindex="-1">3. GraphQL <a class="header-anchor" href="#_3-graphql" aria-label="Permalink to “3. GraphQL”">​</a></h2><p><strong>GraphQL</strong> — запитна мова для API, розроблена Facebook.</p><h3 id="🔹-основні-характеристики-2" tabindex="-1">🔹 Основні характеристики: <a class="header-anchor" href="#🔹-основні-характеристики-2" aria-label="Permalink to “🔹 Основні характеристики:”">​</a></h3><ul><li>Клієнт сам вирішує, які дані йому потрібні</li><li>Один ендпоінт (<code>/graphql</code>) для всіх запитів</li><li>Працює через POST-запити</li></ul><h3 id="✅-переваги-2" tabindex="-1">✅ Переваги: <a class="header-anchor" href="#✅-переваги-2" aria-label="Permalink to “✅ Переваги:”">​</a></h3><ul><li>Ефективність (отримуєш лише потрібні поля)</li><li>Ідеальний для мобільних застосунків</li><li>Гнучкий і масштабований</li></ul><h3 id="❌-недоліки-2" tabindex="-1">❌ Недоліки: <a class="header-anchor" href="#❌-недоліки-2" aria-label="Permalink to “❌ Недоліки:”">​</a></h3><ul><li>Потрібне додаткове навчання</li><li>Ускладнене кешування</li></ul><hr><h2 id="_4-grpc-google-remote-procedure-call" tabindex="-1">4. gRPC (Google Remote Procedure Call) <a class="header-anchor" href="#_4-grpc-google-remote-procedure-call" aria-label="Permalink to “4. gRPC (Google Remote Procedure Call)”">​</a></h2><p><strong>gRPC</strong> — високопродуктивний фреймворк для віддалених викликів, заснований на HTTP/2.</p><h3 id="🔹-основні-характеристики-3" tabindex="-1">🔹 Основні характеристики: <a class="header-anchor" href="#🔹-основні-характеристики-3" aria-label="Permalink to “🔹 Основні характеристики:”">​</a></h3><ul><li>Працює через HTTP/2</li><li>Використовує Protocol Buffers (protobuf) замість JSON/XML</li><li>Підтримує двосторонній стрімінг</li></ul><h3 id="✅-переваги-3" tabindex="-1">✅ Переваги: <a class="header-anchor" href="#✅-переваги-3" aria-label="Permalink to “✅ Переваги:”">​</a></h3><ul><li>Дуже швидкий</li><li>Ідеальний для мікросервісів</li><li>Підтримує кілька мов програмування</li></ul><h3 id="❌-недоліки-3" tabindex="-1">❌ Недоліки: <a class="header-anchor" href="#❌-недоліки-3" aria-label="Permalink to “❌ Недоліки:”">​</a></h3><ul><li>Менш зручний для використання у веб-браузерах</li><li>Складний у налаштуванні</li></ul><hr><h2 id="висновок" tabindex="-1">Висновок <a class="header-anchor" href="#висновок" aria-label="Permalink to “Висновок”">​</a></h2><table tabindex="0"><thead><tr><th>Тип API</th><th>Формат</th><th>Протокол</th><th>Ідеально для</th></tr></thead><tbody><tr><td>REST</td><td>JSON/XML</td><td>HTTP/HTTPS</td><td>Публічні веб-сервіси</td></tr><tr><td>SOAP</td><td>XML</td><td>HTTP/HTTPS</td><td>Корпоративні системи</td></tr><tr><td>GraphQL</td><td>JSON</td><td>HTTP/HTTPS</td><td>Гнучкі клієнтські застосунки</td></tr><tr><td>gRPC</td><td>Protobuf</td><td>HTTP/2</td><td>Мікросервіси та високонавантажені системи</td></tr></tbody></table><hr><h2 id="📎-корисні-посилання" tabindex="-1">📎 Корисні посилання <a class="header-anchor" href="#📎-корисні-посилання" aria-label="Permalink to “📎 Корисні посилання”">​</a></h2><ul><li><a href="https://graphql.org/learn/" target="_blank" rel="noreferrer">GraphQL Docs</a></li><li><a href="https://restfulapi.net/" target="_blank" rel="noreferrer">REST API Tutorial</a></li><li><a href="https://www.w3schools.com/xml/xml_soap.asp" target="_blank" rel="noreferrer">What is SOAP?</a></li><li><a href="https://grpc.io/docs/" target="_blank" rel="noreferrer">gRPC Overview</a></li></ul>',44)]))}const b=e(t,[["render",o]]);export{P as __pageData,b as default};
